<template>
  <button 
    class="back-to-top" 
    :class="{ show: isVisible }" 
    @click="scrollToTop"
    aria-label="返回顶部"
  >
    <BaseIcon>
      <polyline points="18 15 12 9 6 15"/>
    </BaseIcon>
  </button>
</template>

<script>
import BaseIcon from './BaseIcon.vue'

export default {
  name: 'BackToTop',
  components: {
    BaseIcon
  },
  data() {
    return {
      isVisible: false
    }
  },
  mounted() {
    window.addEventListener('scroll', this.handleScroll)
  },
  unmounted() {
    window.removeEventListener('scroll', this.handleScroll)
  },
  methods: {
    handleScroll() {
      this.isVisible = window.scrollY > 400
    },
    scrollToTop() {
      window.scrollTo({
        top: 0,
        behavior: 'smooth'
      })
    }
  }
}
</script>
