<script>
export default {
  name: 'ToastMessage',
  data() {
    return {
      visible: false,
      message: '代码已复制'
    }
  },
  methods: {
    show(msg = '代码已复制') {
      this.message = msg
      this.visible = true
      setTimeout(() => {
        this.visible = false
      }, 2000)
    }
  }
}
</script>

