<template>
  <div>
    <Header />
    <main class="search-page-main">
      <div class="container">
        <div class="search-header">
          <h1 class="search-title">
            {{ $t('search.title') }}: <span class="query-text">"{{ query }}"</span>
          </h1>
          <p class="search-stats">{{ $t('search.title') === '搜索结果' ? '找到' : 'Found' }} {{ filteredResults.length }} {{ $t('search.title') === '搜索结果' ? '个相关教程' : 'related tutorials' }}</p>
        </div>

        <div v-if="filteredResults.length > 0" class="search-grid">
          <router-link 
            v-for="result in filteredResults" 
            :key="result.path" 
            :to="result.path" 
            class="search-item-card"
          >
            <div class="search-item-info">
              <span class="search-item-meta">{{ result.meta }}</span>
              <h3 class="search-item-title">{{ result.title }}</h3>
              <p class="search-item-desc">{{ result.keywords }}</p>
            </div>
            <BaseIcon size="sm" class="search-item-arrow">
              <polyline points="9 18 15 12 9 6"/>
            </BaseIcon>
          </router-link>
        </div>

        <div v-else class="no-results">
          <div class="no-results-icon">
            <BaseIcon size="xl" color="tertiary">
              <circle cx="11" cy="11" r="8"/>
              <line x1="21" y1="21" x2="16.65" y2="16.65"/>
            </BaseIcon>
          </div>
          <h2>{{ $t('search.noResults') }}</h2>
          <p>{{ $t('search.title') === '搜索结果' ? '请尝试换个关键词搜索，或者浏览我们的' : 'Please try a different keyword, or browse our' }} <router-link to="/languages">{{ $t('search.title') === '搜索结果' ? '编程语言索引' : 'Programming Language Index' }}</router-link>。</p>
        </div>
      </div>
    </main>
    <Footer />
  </div>
</template>

<script>
import AppHeader from '../components/Header.vue'
import AppFooter from '../components/Footer.vue'
import BaseIcon from '../components/BaseIcon.vue'
import { searchIndex } from '../data/searchIndex'

export default {
  name: 'SearchResults',
  components: {
    Header: AppHeader,
    Footer: AppFooter,
    BaseIcon
  },
  computed: {
    query() {
      return this.$route.query.q || ''
    },
    filteredResults() {
      const q = this.query.trim().toLowerCase()
      if (!q) return []
      
      return searchIndex
        .map(item => {
          const haystack = `${item.title} ${item.meta || ''} ${item.keywords || ''}`.toLowerCase()
          const pos = haystack.indexOf(q)
          return pos === -1 ? null : { ...item, score: pos }
        })
        .filter(item => item !== null)
        .sort((a, b) => a.score - b.score)
    }
  }
}
</script>

