            :placeholder="$t('nav.search')" 
            v-model="searchQuery" 
            @input="handleSearch" 
            @blur="closeSearchResults"
            @keyup.enter="goToSearchPage"
          >
          <div class="search-results" v-if="searchResults.length > 0" @mousedown.prevent>
            <router-link 
              v-for="result in searchResults" 
              :key="result.path"
              :to="result.path"
              class="search-result-item"
              @click="clearSearch"
            >
              <div class="result-title">{{ result.title }}</div>
              <div class="result-meta">{{ result.meta }}</div>
            </router-link>
          </div>
        </div>
        <div class="lang-switch">
          <button 
            class="lang-btn" 
            :class="{ active: $i18n.locale === 'zh-CN' }"
            @click="switchLang('zh-CN')"
          >中</button>
          <button 
            class="lang-btn" 
            :class="{ active: $i18n.locale === 'en' }"
            @click="switchLang('en')"
          >EN</button>
        </div>
