<template>
  <div>
    <Header />
    <main class="tutorial-main">
      <aside class="tutorial-sidebar">
        <div class="sidebar-header">
          <h3>{{ tutorialTitle }}</h3>
          <span class="chapter-count">{{ chapters.length }} {{ $t('tutorial.chapters') }}</span>
        </div>
        <nav class="chapter-nav">
          <div v-for="(chapter, index) in chapters" :key="index" class="chapter" :class="{ active: expandedChapters.includes(index) }">
            <div class="chapter-title" @click="toggleChapter(index)">
              {{ chapter.title }}
              <BaseIcon class="chevron" size="sm" :class="{ rotated: expandedChapters.includes(index) }">
                <polyline points="6 9 12 15 18 9"/>
              </BaseIcon>
            </div>
            <ul v-show="expandedChapters.includes(index)" class="lesson-list">
              <li v-for="lesson in chapter.lessons" :key="lesson.id" :class="{ active: currentLessonId === lesson.id }">
                <a :href="'#' + lesson.id" @click.prevent="scrollToSection(lesson.id)">{{ lesson.title }}</a>
              </li>
            </ul>
          </div>
        </nav>
      </aside>
      
      <div class="tutorial-content">
        <div class="tutorial-nav top">
          <router-link v-if="prevTutorial" :to="prevTutorial.path" class="nav-btn prev">{{ $t('tutorial.prevTutorial', { name: prevTutorial.name }) }}</router-link>
          <div v-else class="nav-placeholder"></div>
          <router-link v-if="nextTutorial" :to="nextTutorial.path" class="nav-btn next">{{ $t('tutorial.nextTutorial', { name: nextTutorial.name }) }}</router-link>
          <div v-else class="nav-placeholder"></div>
        </div>

        <div v-if="isEnglishFallback" class="fallback-notice">
          <BaseIcon size="sm"><circle cx="12" cy="12" r="10"/><line x1="12" y1="8" x2="12" y2="12"/><line x1="12" y1="16" x2="12.01" y2="16"/></BaseIcon>
          <span>{{ $t('tutorial.englishFallback') }}</span>
        </div>

        <div v-html="tutorialContent" ref="contentArea"></div>

        <div class="tutorial-nav bottom">
          <router-link v-if="prevTutorial" :to="prevTutorial.path" class="nav-btn prev">{{ $t('tutorial.prevTutorial', { name: prevTutorial.name }) }}</router-link>
          <div v-else class="nav-placeholder"></div>
          <router-link v-if="nextTutorial" :to="nextTutorial.path" class="nav-btn next">{{ $t('tutorial.nextTutorial', { name: nextTutorial.name }) }}</router-link>
          <div v-else class="nav-placeholder"></div>
        </div>
      </div>
    </main>
    <Footer />
  </div>
</template>

<script>
import AppHeader from '../components/Header.vue'
import AppFooter from '../components/Footer.vue'
import BaseIcon from '../components/BaseIcon.vue'
import { tutorialData } from '../data/tutorials'
import { tutorialDataEn } from '../data/tutorials_en'

export default {
  name: 'TutorialPage',
  components: { Header: AppHeader, Footer: AppFooter, BaseIcon },
  data() {
    return {
      expandedChapters: [0],
      currentLessonId: '',
      lang: this.$route.params.lang
    }
  },
  computed: {
    currentData() {
      return this.$i18n.locale === 'en' ? tutorialDataEn : tutorialData
    },
    tutorial() {
      if (this.$i18n.locale === 'en') {
        return this.currentData[this.lang] || tutorialData[this.lang] || this.currentData['html']
      }
      return this.currentData[this.lang] || this.currentData['html']
    },
    isEnglishFallback() {
      return this.$i18n.locale === 'en' && !this.currentData[this.lang] && !!tutorialData[this.lang]
    },
    tutorialTitle() {
      return this.tutorial.title
    },
    chapters() {
      return this.tutorial.chapters || []
    },
    tutorialContent() {
      return this.tutorial.content || ''
    },
    prevTutorial() {
      const order = ['html', 'css', 'javascript', 'typescript', 'react', 'vue', 'python', 'java', 'go', 'rust', 'c', 'cpp']
      const idx = order.indexOf(this.lang)
      if (idx > 0) {
        const prev = order[idx - 1]
        return { name: this.currentData[prev]?.title || prev, path: `/tutorial/${prev}` }
      }
      return null
    },
    nextTutorial() {
      const order = ['html', 'css', 'javascript', 'typescript', 'react', 'vue', 'python', 'java', 'go', 'rust', 'c', 'cpp']
      const idx = order.indexOf(this.lang)
      if (idx >= 0 && idx < order.length - 1) {
        const next = order[idx + 1]
        return { name: this.currentData[next]?.title || next, path: `/tutorial/${next}` }
      }
      return null
    }
  },
  watch: {
    '$route.params.lang'(newLang) {
      this.lang = newLang
      this.expandedChapters = [0]
      this.currentLessonId = ''
      this.$nextTick(() => {
        this.initContentFeatures()
      })
    },
    '$i18n.locale'() {
      this.$nextTick(() => {
        this.initContentFeatures()
      })
    }
  },
  mounted() {
    this.initContentFeatures()
    window.addEventListener('scroll', this.handleScroll)
  },
  unmounted() {
    window.removeEventListener('scroll', this.handleScroll)
  },
  methods: {
    toggleChapter(index) {
      const idx = this.expandedChapters.indexOf(index)
      if (idx > -1) {
        this.expandedChapters.splice(idx, 1)
      } else {
        this.expandedChapters.push(index)
      }
    },
    initContentFeatures() {
      if (window.Prism) {
        window.Prism.highlightAll()
      }
    },
    handleScroll() {
      const sections = document.querySelectorAll('.content-section')
      let currentId = ''
      sections.forEach(section => {
        const top = section.offsetTop
        if (window.scrollY >= top - 150) {
          currentId = section.id
        }
      })
      if (currentId && this.currentLessonId !== currentId) {
        this.currentLessonId = currentId
      }
    },
    scrollToSection(id) {
      this.currentLessonId = id
      const el = document.getElementById(id)
      if (el) {
        const offset = 100
        const bodyRect = document.body.getBoundingClientRect().top
        const elementRect = el.getBoundingClientRect().top
        const elementPosition = elementRect - bodyRect
        const offsetPosition = elementPosition - offset
        window.scrollTo({
          top: offsetPosition,
          behavior: 'smooth'
        })
      }
    }
  }
}
</script>